"use strict";(self.webpackChunkwoocommerce_shopify_connector=self.webpackChunkwoocommerce_shopify_connector||[]).push([[188],{6524(e,o,i){i.r(o),i.d(o,{comp:()=>r,data:()=>n});var t=i(641);const a={},r=(0,i(6262).A)(a,[["render",function(e,o){return(0,t.uX)(),(0,t.CE)("div",null,[...o[0]||(o[0]=[(0,t.Fv)('<h1 id="features-of-woocommerce-shopify-connector" tabindex="-1"><a class="header-anchor" href="#features-of-woocommerce-shopify-connector"><span>Features of WooCommerce Shopify Connector</span></a></h1><p>The WooCommerce Shopify Connector provides a complete solution to synchronize data between WooCommerce and Shopify stores efficiently.</p><hr><h2 id="key-features" tabindex="-1"><a class="header-anchor" href="#key-features"><span>Key Features</span></a></h2><ul><li>Map Shopify collections with WooCommerce categories.</li><li>Import Shopify products into WooCommerce with ease.</li><li>Set a default category for imported products.</li><li>Support for <strong>Simple</strong> and <strong>Variable</strong> product types (import/export).</li><li>Import complete product details: <ul><li>Images (base &amp; gallery)</li><li>Name, price, SKU</li><li>Description, quantity, weight</li><li>Attributes</li></ul></li><li>Imported products function like native WooCommerce products.</li><li>One-click manual product update option.</li><li>Export WooCommerce products to Shopify.</li><li>Import Shopify orders into WooCommerce.</li><li>Set default order status for imported orders.</li><li>Add and manage multiple Shopify accounts.</li><li>Export orders to Shopify with a single click.</li><li>Real-time auto-sync for orders and products.</li><li>Auto-sync product details like price, SKU, stock, and category.</li><li>Apply price rules for import/export with real-time updates.</li><li>Two-way real-time product synchronization (WooCommerce ↔ Shopify).</li><li>Two-way automatic inventory management on new orders.</li><li>Sync unlimited orders without any monthly fees.</li><li>Import additional data: <ul><li>Customers</li><li>Pages</li><li>Blogs</li><li>Coupons</li></ul></li><li>Import and manage shipping and tax from Shopify.</li><li>Display Shopify tracking details in WooCommerce orders.</li></ul><hr><h2 id="advanced-features" tabindex="-1"><a class="header-anchor" href="#advanced-features"><span>Advanced Features</span></a></h2><ul><li><strong>Real-Time Sync – Fields to Update</strong><br> Control which product fields (price, images, categories, SKU, stock, etc.) are synchronized between WooCommerce and Shopify in real time.</li></ul><hr><h2 id="important-notes" tabindex="-1"><a class="header-anchor" href="#important-notes"><span>Important Notes</span></a></h2><ul><li>For sale products in Shopify: <ul><li><strong>Price</strong> = Sale price</li><li><strong>Compare at Price</strong> = Regular price</li></ul></li><li>Only products with up to <strong>3 variation attributes</strong> can be exported to Shopify.</li><li>Shopify store <strong>location must be configured</strong> for product export.</li><li>Fully compatible with <strong>GraphQL API</strong>.</li></ul><hr><h2 id="real-time-synchronization" tabindex="-1"><a class="header-anchor" href="#real-time-synchronization"><span>Real-Time Synchronization</span></a></h2><p>The connector supports real-time synchronization in both directions (Shopify ↔ WooCommerce):</p><ul><li><p><strong>Automatic Creation</strong><br> New products created in Shopify are automatically created in WooCommerce.</p></li><li><p><strong>Automatic Update</strong><br> Product changes (price, stock, SKU, description, etc.) are synced instantly.</p></li><li><p><strong>Automatic Deletion</strong><br> Deleted products in Shopify are also removed from WooCommerce.</p></li></ul><hr><h2 id="automatic-inventory-management" tabindex="-1"><a class="header-anchor" href="#automatic-inventory-management"><span>Automatic Inventory Management</span></a></h2><ul><li>Stock levels are automatically updated when products are sold or modified.</li><li>Out-of-stock products in Shopify are reflected in WooCommerce.</li><li>Works in both directions based on sync configuration.</li><li>Reduces manual inventory management efforts.</li></ul><hr>',19)])])}]]),n=JSON.parse('{"path":"/documentation/features.html","title":"Features","lang":"en-US","frontmatter":{"title":"Features","description":"Features of WooCommerce Shopify Connector"},"git":{"contributors":[{"name":"shakir.hussain","username":"","email":"shakir.hussain421@webkul.in","commits":1},{"name":"nikhilsharma.qa322","username":"","email":"nikhilsharma.qa322@webkul.in","commits":2}],"changelog":[{"hash":"666ba14683051994598158696c03d1a6283a5c17","time":1773821735000,"email":"nikhilsharma.qa322@webkul.in","author":"nikhilsharma.qa322","message":"update the content, images and blog link"},{"hash":"0a7b954188f94a182eda2a23f9794339b9a9129b","time":1773408353000,"email":"nikhilsharma.qa322@webkul.in","author":"nikhilsharma.qa322","message":"update the blog content and add the images"},{"hash":"2cb5b7e87b994a68b2c6603c7b258716d037a422","time":1772201950000,"email":"shakir.hussain421@webkul.in","author":"shakir.hussain","message":"move created new blog to dev"}]},"filePathRelative":"documentation/features.md"}')}}]);